<?php namespace App\Repositories\Hr;use App\Repositories\BaseRepository;use App\Models\Hr\Recruitment;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class RecruitmentRepository extends BaseRepository{    public function __construct(Recruitment $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findByDepartment(int $departmentId): Collection    {        return $this->findByField('department_id', $departmentId);    }    public function findByDesignation(int $designationId): Collection    {        return $this->findByField('designation_id', $designationId);    }    public function getOpenPositions(): Collection    {        return $this->query()->where('status', 'open')->where('closing_date', '>=', now())->get();    }    public function getClosedPositions(): Collection    {        return $this->query()->where('status', 'closed')->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('posted_date', [$startDate, $endDate])->get();    }    public function searchRecruitments(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->orWhere('requirements', 'like', "%{$keyword}%")->get();    }    public function closePosition(int $id): bool    {        return $this->update($id, ['status' => 'closed', 'closed_at' => now()]);    }    public function reopenPosition(int $id): bool    {        return $this->update($id, ['status' => 'open', 'closed_at' => null]);    }}